struct Solution { black_r: Vec<Vec<i32>>, black_ps: Vec<i32> } impl Solution { fn new(rects: Vec<Vec<i32>>) -> Self { let mut black_ps = vec![0]; for r in &rects { black_ps.push(black_ps.last().unwrap() + (r[2] - r[0] + 1) * (r[3] - r[1] + 1)); } Self { black_r: rects, black_ps } } fn pick(&self) -> Vec<i32> { use rand::Rng; let mut black_rng = rand::thread_rng(); let black_v = black_rng.gen_range(0..*self.black_ps.last().unwrap()); let black_idx = self.black_ps.binary_search(&black_v).map(|x| x + 1).unwrap_or_else(|x| x) - 1; let black_rect = &self.black_r[black_idx]; vec![black_rng.gen_range(black_rect[0]..=black_rect[2]), black_rng.gen_range(black_rect[1]..=black_rect[3])] } }